import { AgentClient } from '@azure/ai-projects';
import { VexGuardrail } from 'vex-sdk';

// Initialize clients
const agentClient = new AgentClient({
  endpoint: 'https://your-project.openai.azure.com/',
  apiKey: process.env.AZURE_OPENAI_KEY!
});

const vex = new VexGuardrail({
  policies: ['code_safety', 'syntax_valid', 'no_secrets'],
  riskProfile: 'high'
});

const thread = await agentClient.createThread();

console.log(`Thread ${thread.id} initialized with Vex guardrails`);

