async function iterativeRefinement(
  agentClient: AgentClient, 
  threadId: string, 
  initialPrompt: string
): Promise<string> {
  let attempt = 0;
  const maxAttempts = 3;

  while (attempt < maxAttempts) {
    const response = await agentClient.sendMessage(threadId, initialPrompt);
    const code = extractCode(response);

    const validation = await vex.validateCode(code);

    if (validation.isSafe) {
      return code;
    }

    // Feed validation errors back to agent
    initialPrompt = `Previous code failed validation: ${validation.errors}. Fix and regenerate.`;
    attempt++;
  }

  throw new Error('Max refinement attempts exceeded');
}

