from vex_sdk import DependencyValidator, SyntaxValidator

class CodeGenerationGuardrail:
    def __init__(self):
        self.syntax = SyntaxValidator(languages=['python', 'javascript'])
        self.deps = DependencyValidator(
            blocked_packages=['cryptography', 'requests'],
            azure_safe=True
        )

    def validate(self, code: str) -> dict:
        results = {
            'syntax_valid': self.syntax.validate(code),
            'deps_safe': self.deps.scan(code),
            'no_azure_creds': not re.search(r'az://|azure://', code)
        }
        return {'approved': all(results.values()), 'details': results}

import { TokenMonitor, ThreadManager } from 'vex-sdk';

class AzureAgentGuardrail {
  constructor() {
    this.tokenMonitor = new TokenMonitor({ limit: 128000 });
    this.threadManager = new ThreadManager();
  }

  async processAgentResponse(threadId: string, response: any) {
    const tokenCount = this.tokenMonitor.countTokens(response);

    if (tokenCount > 120000) {
      // Graceful degradation
      const summary = await this.threadManager.summarizeThread(threadId);
      await this.threadManager.truncateThread(threadId, summary);
      return { status: 'truncated', summary };
    }

    return { status: 'ok', tokens: tokenCount };
  }
}
